<script lang="ts">
  const html: string = "<h1>Collection List</h1>\n\n<p>A collection list is a compact <code>&lt;ul&gt;</code> of related items — typically articles, events, search results, or news entries — rendered as a vertical stack of <code>collection-list-item</code> children.</p>\n\n<p>Use it whenever a page presents many small content cards that share a template (heading, optional meta, optional thumbnail) and should be announced as a single list to assistive technology.</p>\n\n<h2>Implementation Notes</h2>\n\n<ul>\n<li>Renders a native <code>&lt;ul&gt;</code> element with class <code>collection-list</code></li>\n<li><code>label</code> prop is <strong>optional</strong> — when supplied it sets <code>aria-label</code> on the list</li>\n<li>Children are expected to be <code>collection-list-item</code> elements</li>\n<li>The <code>&lt;ul&gt;</code> semantics provide list count and item position to screen readers</li>\n<li>Pass-through attributes are forwarded to the root <code>&lt;ul&gt;</code></li>\n</ul>\n\n<h2>Composition</h2>\n\n<p>This component is part of the <code>*List</code> <code>*ListItem</code> composition pattern. Pair it with <code>CollectionListItem</code> children to form a complete collection.</p>\n\n<h2>Props</h2>\n\n<ul>\n<li><code>label</code>: string (optional) -- aria-label for the list</li>\n<li><code>children</code>: slot -- <code>collection-list-item</code> children</li>\n<li><code>...restProps</code>: any additional HTML attributes</li>\n</ul>\n\n<h2>Usage</h2>\n\n<p>Basic collection of articles:</p>\n\n<pre><code class=\"language-html\">&lt;CollectionList label=\"Recent articles\"&gt;\n  &lt;CollectionListItem heading=\"First post\" meta=\"Jan 5\" /&gt;\n  &lt;CollectionListItem heading=\"Second post\" meta=\"Jan 12\" /&gt;\n&lt;/CollectionList&gt;</code></pre>\n\n<h2>Keyboard Interactions</h2>\n\n<ul>\n<li>Tab: focus moves to interactive descendants (links, buttons) within items</li>\n<li>The list itself is not interactive</li>\n</ul>\n\n<h2>ARIA</h2>\n\n<ul>\n<li>Implicit <code>list</code> role from <code>&lt;ul&gt;</code> element</li>\n<li><code>aria-label</code> is provided when the <code>label</code> prop is set</li>\n<li>Each child contributes a list item via its <code>&lt;li&gt;</code> element</li>\n</ul>\n\n<h2>When to Use</h2>\n\n<ul>\n<li>Use to present a homogeneous series of related content cards.</li>\n<li>Use when items share the same template and should be announced as a single list.</li>\n<li>Use as the body of search results, news feeds, event calendars.</li>\n</ul>\n\n<h2>When Not to Use</h2>\n\n<ul>\n<li>Do not use for navigation menus — use a <code>Nav</code> + <code>List</code> + <code>ListItem</code> composition.</li>\n<li>Do not use for tabular data — use <code>DataTable</code>.</li>\n<li>Do not use for a single item — use the underlying card or article element directly.</li>\n</ul>\n\n<h2>Headless</h2>\n\n<p>Renders only the <code>&lt;ul&gt;</code> semantics. The list spacing, item dividers, and any visual rhythm are entirely the consumer's responsibility.</p>\n\n<h2>Styles</h2>\n\n<p>Consumer CSS targets the <code>collection-list</code> class. Typical treatments remove default list bullets, apply consistent vertical spacing, and add optional dividers between items.</p>\n\n<h2>Testing</h2>\n\n<ul>\n<li>Verify the component renders a <code>&lt;ul&gt;</code> element with class <code>collection-list</code></li>\n<li>Verify <code>aria-label</code> is present when <code>label</code> is supplied</li>\n<li>Verify <code>aria-label</code> is absent when <code>label</code> is omitted</li>\n<li>Verify children render inside the list</li>\n<li>Verify additional HTML attributes pass through to the root <code>&lt;ul&gt;</code></li>\n</ul>\n\n<h2>Advice</h2>\n\n<ul>\n<li><strong>Designers</strong>: Keep item templates consistent so the list reads predictably. Use a generous vertical rhythm to separate items.</li>\n<li><strong>Developers</strong>: Always supply <code>CollectionListItem</code> children. Add <code>label</code> when the list's purpose is not clear from surrounding context.</li>\n</ul>\n\n<h2>Related components</h2>\n\n<ul>\n<li><code>collection-list-item</code> — one item in a collection list with optional image, heading, meta, and description</li>\n</ul>\n\n<h2>References</h2>\n\n<ul>\n<li>US Web Design System Collection: https://designsystem.digital.gov/components/collection/</li>\n<li>HTML <code>&lt;ul&gt;</code>: https://developer.mozilla.org/en-US/docs/Web/HTML/Element/ul</li>\n<li>WCAG 1.3.1 Info and Relationships: https://www.w3.org/WAI/WCAG22/Understanding/info-and-relationships</li>\n</ul>";
  // BEGIN auto-generated component example consts
  const demoHtml: string = "<div class=\"collection-list\" aria-label=\"a compact list of multiple related items such as articles or events\">CollectionList</div>";
  const svelteSource: string = "// In your Svelte component:\nimport CollectionList from \"lily-design-system-svelte-headless/components/CollectionList/CollectionList.svelte\";\n\n<CollectionList>\n  <!-- list children -->\n</CollectionList>\n";
  // END auto-generated component example consts
